  INDEX `ix_rag_embedding_hash`(`hash` ASC) USING BTREE,
  INDEX `ix_rag_embedding_tenant_id`(`tenant_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = DYNAMIC;

